foreach ($u in $data.users) {
    if ($u.studentCode -and $null -ne $studentNames.PSObject.Properties[$u.studentCode]) { $u.displayName = $studentNames.$($u.studentCode) }
    if ($u.lecturerCode -and $null -ne $lecturerNames.PSObject.Properties[$u.lecturerCode]) { $u.displayName = $lecturerNames.$($u.lecturerCode) }
}
foreach ($x in $data.studentClasses) { if ($null -ne $classDescriptions.PSObject.Properties[$x.code]) { $x.description = $classDescriptions.$($x.code) } }
foreach ($x in $data.courses) { if ($null -ne $courseData.PSObject.Properties[$x.code]) { $x.name = $courseData.$($x.code).Name; $x.description = $courseData.$($x.code).Description } }
foreach ($x in $data.semesters) { if ($x.code -eq "2025T1") { $x.description = "Học kỳ 1 năm học 2025-2026" } }
foreach ($x in $data.studentProfiles) { if ($null -ne $studentNames.PSObject.Properties[$x.studentCode]) { $x.fullName = $studentNames.$($x.studentCode); $x.note = "Sinh viên hệ chính quy" } }
foreach ($x in $data.lecturerProfiles) { if ($null -ne $lecturerNames.PSObject.Properties[$x.code]) { $x.fullName = $lecturerNames.$($x.code); $x.note = $lecturerNotes.$($x.code) } }
foreach ($x in $data.courseOfferings) {
    if ($null -ne $courseData.PSObject.Properties[$x.courseCode]) { $section = ($x.code -split "-")[-1]; $x.displayName = "$($x.courseCode) - $($courseData.$($x.courseCode).Name) - 2025T1 - $section" }
    if ($null -ne $offeringDescriptions.PSObject.Properties[$x.code]) { $x.description = $offeringDescriptions.$($x.code) }
}

$json = $data | ConvertTo-Json -Depth 8
$utf8 = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText((Resolve-Path $path), $json, $utf8)
